fun findConnectedCities(cities: List<String>, rivers: List<String>): List<String> {
    val connectedCities = mutableListOf<String>()

    for (city in cities) {
        var connected = true

        for (river in rivers) {
            if (city !in river) {
                connected = false
                break
            }
        }

        if (connected) {
            connectedCities.add(city)
        }
    }

    return connectedCities
}

